import pymongo

def find_user_by_email(email, connection_string="mongodb://localhost:27017/", db_name="your_database", collection_name="users"):
    client = pymongo.MongoClient(connection_string)
    db = client[db_name]
    collection = db[collection_name]
    user = collection.find_one({"email": email})
    client.close()
    return user

